import{api as d}from"./api.DG-MfJ3R.js";const e=t=>document.getElementById(t);function m(t){const s=e("stats-error");s.classList.remove("hidden"),s.textContent="Ошибка: "+t}async function g(){try{const t=await d.stats();e("m-total").textContent=String(t.totalInteractions),e("m-rate").textContent=Math.round((t.successRate??0)*100)+"%",e("m-skills").textContent=String(t.totalSkills);const s=t.skillBased+t.direct,l=s>0?Math.round(t.skillBased/s*100):0;e("m-skillshare").textContent=l+"%";const x=s>0?t.skillBased/s*100:0,h=s>0?t.direct/s*100:0;e("bar-skill").style.width=x+"%",e("bar-direct").style.width=h+"%",e("lbl-skill").textContent=String(t.skillBased),e("lbl-direct").textContent=String(t.direct);const a=e("byday"),c=e("byday-empty");a.innerHTML="";const o=t.byDay||[];if(o.length===0)c.classList.remove("hidden");else{c.classList.add("hidden");const r=Math.max(1,...o.map(n=>n.total));for(const n of o){const i=document.createElement("div");i.className="group relative flex flex-1 flex-col items-center justify-end gap-1";const y=n.skill/r*100,f=n.direct/r*100;i.innerHTML=`
            <div class="flex w-full max-w-[28px] flex-col-reverse overflow-hidden rounded-t" style="height:140px">
              <div class="w-full bg-sky-500/80" style="height:${f}%"></div>
              <div class="w-full bg-violet-500/80" style="height:${y}%"></div>
            </div>
            <div class="mono text-[9px] text-gray-500">${n.date.slice(5)}</div>
            <div class="pointer-events-none absolute -top-7 hidden rounded bg-black px-2 py-1 text-[10px] text-gray-200 group-hover:block">${n.total} (н:${n.skill}/п:${n.direct})</div>
          `,a.appendChild(i)}}}catch(t){m(t instanceof Error?t.message:String(t))}}e("reflect-btn").addEventListener("click",async()=>{const t=e("reflect-out"),s=e("reflect-btn");s.disabled=!0,t.textContent="Анализ…";try{const l=await d.reflect();t.textContent=l.markdown||"(пустой отчёт)"}catch(l){t.textContent="Ошибка: "+(l instanceof Error?l.message:l)}finally{s.disabled=!1}});g();
